#include "ca6k_00402_custom_tiling.h"
#include "register/op_def_registry.h"
#include <vector>

namespace optiling {

static inline uint32_t productExceptDim(const std::vector<int64_t>& shape, int32_t dim) {
    uint32_t prod = 1;
    for (size_t i = 0; i < shape.size(); i++) {
        if (static_cast<int32_t>(i) != dim)
            prod *= static_cast<uint32_t>(shape[i]);
    }
    return prod;
}

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 32;

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k00402CustomTilingData tiling;
    const uint32_t totalLength =
        static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *dimPtr = attrs->GetAttrPointer<int64_t>(0);
    int64_t dim = *dimPtr;
    // Handle negative dim
    const auto& shape = context->GetInputShape(0)->GetOriginShape().GetDim();
    int32_t ndim = static_cast<int32_t>(shape.size());
    if (dim < 0) dim += ndim;
    if (dim < 0 || dim >= ndim) {
        return ge::GRAPH_FAILED;
    }

    uint32_t reductionSize = static_cast<uint32_t>(shape[dim]);
    uint32_t outerSize = productExceptDim(shape, static_cast<int32_t>(dim));

    // blockDim: at most 24, also ensure at least 1
    uint32_t blockDim = outerSize;
    if (blockDim > 24) blockDim = 24;
    if (blockDim == 0) blockDim = 1;
    context->SetBlockDim(blockDim);

    uint32_t chunkSize = (outerSize + blockDim - 1) / blockDim;
    if (chunkSize == 0) chunkSize = 1;

    tiling.set_totalLength(totalLength);
    tiling.set_outerSize(outerSize);
    tiling.set_reductionSize(reductionSize);
    tiling.set_chunkSize(chunkSize);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

}

